package be.schaubroeck.lpb.rkm.rekenmotor.service;

import be.schaubroeck.lpb.rkm.rekenmotor.keys.MoneyKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBasisRszKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenPatronaalRszKey;
import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.util.InitializeAdmin;
import org.joda.time.LocalDate;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.jdbc.core.JdbcTemplate;
import org.springframework.jdbc.core.SqlParameterValue;
import org.springframework.transaction.annotation.Transactional;

import javax.sql.DataSource;
import java.sql.Types;
import java.util.Arrays;
import java.util.List;
import java.util.Set;
import java.util.stream.Collectors;

@Transactional
public class StandaardPens2AntwerpenService implements Pens2AntwerpenService {

    @Autowired
    private DataSource dataSource;

    private static final String GET_KEY_OTHER_SQL = "select sum(rb.bedrag) from rekenhoofd rh" + " join opdracht_master om on om.id=rh.opdrachtid"
            + " join rekenlijn rl on rl.rekenhoofdid=rh.id " + " join rekenbedrag rb on rl.id=rb.rekenlijnid"
            + " where bedragtypectid=? and om.persoonId=? and rh.begindatum!=? and year(rh.begindatum)=?";

    private static final String BIJDRAGE_KEY_IDS_STRING = Arrays.toString(
            new Integer[]{RekenPatronaalRszKey.PATRONALE_BIJDRAGE_TWEEDE_PENSIOENPIJLER_KEY.toEnumType().getId(),
                    RekenPatronaalRszKey.PATRONALE_BIJDRAGE_BONUS_TWEEDE_PENSIOENPIJLER_KEY.toEnumType().getId()}).replace('[', '(').replace(']', ')');

    private static final String FIND_GEREKENDE_DATUMS_SQL =
            "select distinct rh.begindatum from rekenhoofd rh" + " join opdracht_master om on om.id=rh.opdrachtid"
                    + " join rekenlijn rl on rl.rekenhoofdid=rh.id " + " join rekenbedrag rb on rl.id=rb.rekenlijnid" + " where bedragtypectid in "
                    + BIJDRAGE_KEY_IDS_STRING + " and om.persoonId=? and rh.begindatum!=? and year(rh.begindatum)=?";

    @InitializeAdmin
    @Override
    public Set<LocalDate> findGerekendeMaandenPatronaleBijdrageTweedePensioenPijlerOther(Admin admin, Persoon persoon, LocalDate huidigeBegindatum) {
        JdbcTemplate jdbc = new JdbcTemplate(dataSource);

        Object[] args = new Object[3];
        args[0] = new SqlParameterValue(Types.INTEGER, persoon.getId());
        args[1] = new SqlParameterValue(Types.DATE, new java.sql.Date(huidigeBegindatum.toDate().getTime()));
        args[2] = new SqlParameterValue(Types.INTEGER, huidigeBegindatum.getYear());
        List<java.sql.Date> resultaat = jdbc.queryForList(FIND_GEREKENDE_DATUMS_SQL, args, java.sql.Date.class);
        return resultaat.stream().map(LocalDate::fromDateFields).collect(Collectors.toSet());
    }

    @InitializeAdmin
    @Override
    public Money getPatronaleBijdrageTweedePensioenPijlerOther(Admin admin, Persoon persoon, LocalDate huidigeBegindatum) {
        return executeQuery(persoon, RekenPatronaalRszKey.PATRONALE_BIJDRAGE_TWEEDE_PENSIOENPIJLER_KEY, huidigeBegindatum);
    }

    @InitializeAdmin
    @Override
    public Money getPatronaleBijdrageBonusTweedePensioenPijlerOther(Admin admin, Persoon persoon, LocalDate huidigeBegindatum) {
        return executeQuery(persoon, RekenPatronaalRszKey.PATRONALE_BIJDRAGE_BONUS_TWEEDE_PENSIOENPIJLER_KEY, huidigeBegindatum);
    }

    @InitializeAdmin
    @Override
    public Money getBasisTweedePensioenPijlerOther(Admin admin, Persoon persoon, LocalDate huidigeBegindatum) {
        return executeQuery(persoon, RekenBasisRszKey.BASIS_TWEEDE_PENSIOENPIJLER_KEY, huidigeBegindatum);
    }

    @InitializeAdmin
    @Override
    public Money getBasisBonusTweedePensioenPijlerOther(Admin admin, Persoon persoon, LocalDate huidigeBegindatum) {
        return executeQuery(persoon, RekenBasisRszKey.BASIS_BONUS_TWEEDE_PENSIOENPIJLER_KEY, huidigeBegindatum);
    }

    private Money executeQuery(Persoon persoon, MoneyKey moneyKey, LocalDate huidigeBegindatum) {
        JdbcTemplate jdbc = new JdbcTemplate(dataSource);

        Object[] args = new Object[4];
        args[0] = new SqlParameterValue(Types.VARCHAR, moneyKey.toEnumType().getId());
        args[1] = new SqlParameterValue(Types.INTEGER, persoon.getId());
        args[2] = new SqlParameterValue(Types.DATE, new java.sql.Date(huidigeBegindatum.toDate().getTime()));
        args[3] = new SqlParameterValue(Types.INTEGER, huidigeBegindatum.getYear());
        String resultaat = jdbc.queryForObject(GET_KEY_OTHER_SQL, args, String.class);

        Money result = Money.ZERO;
        if (resultaat != null) {
            result = new Money(resultaat);
        }
        return result;
    }
}
